func (s *DynamicProtoService) hashProto(proto string) string {
	hash := sha256.Sum256([]byte(proto))
	return hex.EncodeToString(hash[:])
}

func (s *DynamicProtoService) hashProtoWithDeps(mainProto string, deps map[string]string) string {
	var combined strings.Builder
	combined.WriteString(mainProto)
	
	for fileName, content := range deps {
		combined.WriteString(fileName)
		combined.WriteString(content)
	}
	
	hash := sha256.Sum256([]byte(combined.String()))
	return hex.EncodeToString(hash[:])
}

